 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { Button, ButtonVariant } from '@patternfly/react-core';
 4	import { ExpandIcon } from '@patternfly/react-icons';
 5	import SearchBar from './SearchComponent';
 6	import './TopologySearch.scss';
 7	
 8	const TopologySearchBar: React.FC = () => {
 9	  const [isFullScreen, setFullScreen] = React.useState(false);
10	  const { t } = useCustomTranslation();
11	
12	  // Handles for when user exits full screen via `Esc` button
13	  React.useEffect(() => {
14	    const handler = () => {
15	      setFullScreen(!isFullScreen);
16	    };
17	    document.addEventListener('fullscreenchange', handler);
18	    return () => {
19	      document.removeEventListener('fullscreenchange', handler);
20	    };
21	  }, [isFullScreen]);
22	
23	  const toggleFullScreen = (e: React.MouseEvent<HTMLButtonElement>) => {
24	    e.stopPropagation();
25	    const element = document.getElementById('odf-topology');
26	    if (!isFullScreen) {
27	      element
28	        .requestFullscreen()
29	        // eslint-disable-next-line no-console
30	        .catch((error) => console.error(error));
31	    } else {
32	      document
33	        .exitFullscreen()
34	        // eslint-disable-next-line no-console
35	        .catch((error) => console.error(error));
36	    }
37	  };
38	  return (
39	    <div className="odf-topology-search-bar">
40	      <span className="odf-topology-search-bar__search">
41	        <SearchBar />
42	      </span>
43	      <span className="odf-topology-search-bar__expand">
44	        <Button
45	          variant={ButtonVariant.link}
46	          isInline
47	          onClick={toggleFullScreen}
48	          className="odf-topology-search-bar__expand-button"
49	        >
50	          <ExpandIcon className="odf-topology-search-bar__expand-icon" />
51	          {!isFullScreen ? t('Expand to fullscreen') : t('Exit fullscreen')}
52	        </Button>
53	      </span>
54	    </div>
55	  );
56	};
57	
58	export default TopologySearchBar;

